patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 0632f3cfc6dd..2798eed6c136 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2618,6 +2618,17 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       }
     }

+    // ldexp(x, zext(i1 bool)) -> fmul x, (select bool, 2.0, 1.0)
+    // ldexp(x, exp) = x * 2^exp, and when exp is 0 or 1, this is x * 1.0 or x * 2.0
+    Value *Bool;
+    if (match(Exp, m_ZExt(m_Value(Bool))) &&
+        Bool->getType()->isIntOrIntVectorTy(1)) {
+      Type *FloatTy = II->getType();
+      Constant *Two = ConstantFP::get(FloatTy, 2.0);
+      Constant *One = ConstantFP::get(FloatTy, 1.0);
+      Value *Select = Builder.CreateSelect(Bool, Two, One);
+      return BinaryOperator::CreateFMulFMF(Src, Select, II);
+    }
     break;
   }
